@props(['cnaes'])<div class="mb-8 border-b border-white/10 pb-8" x-data='{todosCnaes:@json($cnaes??[]),cnaePrincipalId:@json(request("cnae_principal")),cnaePrincipalTexto:"",cnaePrincipalAberto:false,termoPesquisa:"",cnaesSecundariosSelecionados:[],maxSecundarios:3,cnaeSecundarioAberto:false,init(){if(this.cnaePrincipalId){let a=String(this.cnaePrincipalId),b=this.todosCnaes.find(c=>String(c.id)===a);b&&(this.cnaePrincipalTexto=b.texto)}let d=@json(request("cnaes_secundarios",[]));Array.isArray(d)||(d=[d].filter(Boolean)),d.length>0&&d.forEach(a=>{let b=this.todosCnaes.find(c=>String(c.id)===String(a));b&&!this.cnaesSecundariosSelecionados.find(a=>a.id===b.id)&&this.cnaesSecundariosSelecionados.push(b)})},get cnaesPrincipalFiltrados(){let a=this.cnaePrincipalTexto.toLowerCase();return""===a?this.todosCnaes:this.todosCnaes.filter(b=>b.texto.toLowerCase().includes(a))},get cnaesSecundariosFiltrados(){let a=this.termoPesquisa.toLowerCase();return""===a?this.todosCnaes:this.todosCnaes.filter(b=>b.texto.toLowerCase().includes(a))},selecionarPrincipal(a){this.cnaePrincipalId=a.id,this.cnaePrincipalTexto=a.texto,this.cnaePrincipalAberto=!1},adicionarSecundario(a){this.cnaesSecundariosSelecionados.length>=this.maxSecundarios||(this.cnaesSecundariosSelecionados.find(b=>b.id===a.id)||this.cnaesSecundariosSelecionados.push(a),this.termoPesquisa="",this.cnaeSecundarioAberto=!1)},removerSecundario(a){this.cnaesSecundariosSelecionados.splice(a,1)},limparPrincipal(){this.cnaePrincipalId="",this.cnaePrincipalTexto="",this.cnaePrincipalAberto=!1}}'><h3 class="text-white font-bold text-lg flex items-center gap-2 mb-6"><i class="bi bi-briefcase-fill text-amber-500"></i> Atividade Econômica (CNAE)</h3><div class="grid grid-cols-1 gap-8"><div @click.outside="cnaePrincipalAberto=false"><label class="block text-xs font-bold text-gray-400 uppercase tracking-wider mb-2">CNAE Principal</label><div class="relative"><input type="hidden" name="cnae_principal" :value="cnaePrincipalId"><input type="text" x-model="cnaePrincipalTexto" @focus="cnaePrincipalAberto=true" @input="cnaePrincipalId=``;cnaePrincipalAberto=true" placeholder="Digite o código ou nome da atividade..." class="w-full bg-[#050509] border border-white/10 text-white rounded-xl py-3 px-4 pl-10 focus:ring-2 focus:ring-amber-500/50 focus:border-amber-500 outline-none transition-all placeholder-gray-600"><i class="bi bi-search absolute left-3.5 top-3.5 text-gray-500"></i><div class="absolute inset-y-0 right-0 flex items-center px-4 cursor-pointer" x-show="cnaePrincipalTexto" @click="limparPrincipal"><i class="bi bi-x text-gray-500 hover:text-red-500 transition-colors text-lg"></i></div><div x-show="cnaePrincipalAberto" x-transition class="absolute z-50 w-full mt-2 bg-[#1A1A1E] border border-white/10 rounded-xl shadow-2xl max-h-80 overflow-y-auto" style="display:none"><ul><template x-for="cnae in cnaesPrincipalFiltrados" :key="cnae.id"><li @click="selecionarPrincipal(cnae)" class="px-4 py-3 hover:bg-white/5 hover:text-amber-400 cursor-pointer text-sm text-gray-300 border-b border-white/5 last:border-0 transition-colors"><span x-text="cnae.texto"></span></li></template><li x-show="cnaesPrincipalFiltrados.length===0" class="px-4 py-3 text-sm text-gray-500 text-center">Nenhum CNAE encontrado.</li></ul></div></div></div><div @click.outside="cnaeSecundarioAberto=false"><label class="block text-xs font-bold text-gray-400 uppercase tracking-wider mb-2">CNAEs Secundários <span class="text-[10px] font-normal normal-case text-gray-500 ml-1">(Opcional, máx: <span x-text="maxSecundarios"></span>)</span></label><div class="relative mb-3"><input type="text" x-model="termoPesquisa" @focus="cnaeSecundarioAberto=true" :disabled="cnaesSecundariosSelecionados.length>=maxSecundarios" placeholder="Adicionar atividade secundária..." class="w-full bg-[#050509] border border-white/10 text-white rounded-xl py-3 px-4 pl-10 focus:ring-2 focus:ring-amber-500/50 focus:border-amber-500 outline-none transition-all placeholder-gray-600 disabled:opacity-50"><i class="bi bi-plus-lg absolute left-3.5 top-3.5 text-gray-500"></i><div x-show="cnaeSecundarioAberto" x-transition class="absolute z-50 w-full mt-2 bg-[#1A1A1E] border border-white/10 rounded-xl shadow-2xl max-h-80 overflow-y-auto" style="display:none"><ul><template x-for="cnae in cnaesSecundariosFiltrados" :key="cnae.id"><li @click="adicionarSecundario(cnae)" class="px-4 py-3 hover:bg-white/5 hover:text-amber-400 cursor-pointer text-sm text-gray-300 border-b border-white/5 last:border-0 transition-colors"><span x-text="cnae.texto"></span></li></template></ul></div></div><div class="space-y-2"><template x-for="(cnae, index) in cnaesSecundariosSelecionados" :key="cnae.id"><div class="flex items-center justify-between gap-3 bg-amber-500/10 text-amber-100 px-4 py-3 rounded-lg border border-amber-500/20 text-sm"><input type="hidden" name="cnaes_secundarios[]" :value="cnae.id"><span class="text-sm font-medium leading-tight" x-text="cnae.texto"></span><button type="button" @click="removerSecundario(index)" class="text-amber-400 hover:text-white transition-colors p-1 cursor-pointer"><i class="bi bi-x-lg"></i></button></div></template></div></div></div></div>